    public int error_sync_size() { return 1; }

    private List<ErrorInfo> erroresSintacticos = new ArrayList<>();

    public List<ErrorInfo> getErroresSintacticos() {
        return erroresSintacticos;
    }

    public void syntax_error(Symbol s) {
        // Construir lista de tokens esperados traducidos al español.
        List<Integer> ids = expected_token_ids();

        // Caso especial: draw() sin parámetros.
        if (esDrawSinParametrosVacio(s, ids)) {
            return;
        }

        List<String> esperados = new ArrayList<>();
        for (Integer id : ids) {
            String traducido = TokenLabelProvider.traducir(symbl_name_from_id(id));
            if (!traducido.equals("error")) {
                esperados.add(traducido);
            }
        }

        String encontrado = (s != null && s.value != null)
            ? s.value.toString()
            : TokenLabelProvider.traducir(symbl_name_from_id(s != null ? s.sym : 0));

        int linea   = s != null ? s.left  : 0;
        int columna = s != null ? s.right : 0;

        // Pasamos el menssaje a un formateador experto
        String mensaje = SintaxisErrorFormatter.construirMensaje(esperados, encontrado);

        erroresSintacticos.add(new ErrorInfo(TipoError.SINTACTICO, mensaje, linea, columna));
    }

    private boolean esDrawSinParametrosVacio(Symbol s, List<Integer> ids) {
        if (s == null || s.sym != sym.PAREN_DER) return false;
        if (ids == null || ids.isEmpty()) return false;

        // Esperados típicos al inicio de una expresión.
        List<Integer> inicioExpr = List.of(
            sym.VERTICAL, sym.HORIZONTAL, sym.MONO,
            sym.COLOR_NAME, sym.COLOR_HEX,
            sym.FUNC_POKEMON,
            sym.PAREN_IZQ, sym.COMODIN,
            sym.MENOS, sym.NOT,
            sym.IDENTIFICADOR, sym.NUMBER_LITERAL, sym.INICIO_CADENA
        );
        for (Integer id : ids) {
            if (!inicioExpr.contains(id)) return false;
        }

        // Verificar contexto sintáctico: ... DRAW PAREN_IZQ )
        if (stack == null || stack.size() < 2) return false;
        Symbol top = (Symbol) stack.peek();
        Symbol prev = (Symbol) stack.get(stack.size() - 2);
        return top.sym == sym.PAREN_IZQ && prev.sym == sym.DRAW;
    }

    public void report_error(String message, Object info) {
        // Los errores ya se gestionan en syntax_error; evitar mensajes duplicados.
    }



